// Script Continued Below
(function executeRule(current, previous /*null when async*/) {

	// STRY0065506 - Keep top template task in sync with template
	// See also 'Top Template Task-onUpdate-Sync Template' this rule is the partner rule to keep the field values in sync
	var recTopTemplateTask = new GlideRecordSecure('x_153465_discovert_route_tasks');
	if(recTopTemplateTask.get(current.parent_task_def)){
		// STRY0065506 - go through each sync field and set any changes
		var updateTemplateTask = false;
		// If Acitve flag changes it should update template
		if(current.u_active != previous.u_active){
			updateTemplateTask = true;
			recTopTemplateTask.active = current.u_active;
		}
		// STRY0084986
		if(current.u_tasker_type != previous.u_tasker_type){
			updateTemplateTask = true;
			recTopTemplateTask.tasker_type = current.u_tasker_type;
		}
		if(current.u_signature_instructions != previous.u_signature_instructions){
			updateTemplateTask = true;
			recTopTemplateTask.u_signature_instructions = current.u_signature_instructions;
		}
		if(current.u_reviewer != previous.u_reviewer){
			updateTemplateTask = true;
			recTopTemplateTask.u_reviewer = current.u_reviewer;
		}
		if(current.provide_response != previous.provide_response){
			updateTemplateTask = true;
			recTopTemplateTask.provide_response = current.provide_response;
		}
		if(current.u_on_behalf_of != previous.u_on_behalf_of){
			updateTemplateTask = true;
			recTopTemplateTask.u_on_behalf_of = current.u_on_behalf_of;
		}

		if(current.short_description != previous.short_description){
			updateTemplateTask = true;
			recTopTemplateTask.short_description = current.short_description;
		}
		if(current.description != previous.description){
			updateTemplateTask = true;
			recTopTemplateTask.instructions = current.description;
		}
		if(current.u_objective != previous.u_objective){
			updateTemplateTask = true;
			recTopTemplateTask.u_objective = current.u_objective;
		}
		if(current.classification != previous.classification){
			updateTemplateTask = true;
			recTopTemplateTask.classification = current.classification;
		}
		if(current.u_primary_assignee != previous.u_primary_assignee){
			updateTemplateTask = true;
			recTopTemplateTask.primary_assignee = current.u_primary_assignee;
		}
		if(current.u_primary_office != previous.u_primary_office){
			updateTemplateTask = true;
			recTopTemplateTask.primary_office = current.u_primary_office;
		}
		if(current.u_restricted_group != previous.u_restricted_group){
			updateTemplateTask = true;
			recTopTemplateTask.assigned_to_group = current.u_restricted_group;
		}
		if(current.u_tasking_authority != previous.u_tasking_authority){
			updateTemplateTask = true;
			recTopTemplateTask.tasking_authority = current.u_tasking_authority;
		}
		if(current.u_assigned_member != previous.u_assigned_member){
			updateTemplateTask = true;
			recTopTemplateTask.assigned_to_individual = current.u_assigned_member;
		}

		// STRY0075863
		if(current.u_external_ou != previous.u_external_ou){
			updateTemplateTask = true;
			recTopTemplateTask.u_external_ou = current.u_external_ou;
		}
		if(current.poc_name != previous.poc_name){
			updateTemplateTask = true;
			recTopTemplateTask.poc_name = current.poc_name;
		}
		if(current.outbound != previous.outbound){
			updateTemplateTask = true;
			recTopTemplateTask.outbound = current.outbound;
		}
		if(current.u_internal_contact != previous.u_internal_contact){
			updateTemplateTask = true;
			recTopTemplateTask.u_internal_contact = current.u_internal_contact;
		}
		if(current.u_internal_contact_performing_task != previous.u_internal_contact_performing_task){
			updateTemplateTask = true;
			recTopTemplateTask.u_internal_contact_performing_task = current.u_internal_contact_performing_task;
		}
		// STRY0076610
		if(current.u_wait_for_subtasks_to_finish != previous.u_wait_for_subtasks_to_finish){
			updateTemplateTask = true;
			recTopTemplateTask.u_wait_for_subtasks_to_finish = current.u_wait_for_subtasks_to_finish;
		}
		// STRY0110317 
		if(current.u_duration_days != previous.u_duration_days){
			updateTemplateTask = true;
			recTopTemplateTask.u_duration_days = current.u_duration_days;
		}
		if(current.u_duration_time_due != previous.u_duration_time_due){
			updateTemplateTask = true;
			recTopTemplateTask.u_duration_time_due = current.u_duration_time_due;
		}

		// STRY0076609
		if(current.u_duration != previous.u_duration){
			updateTemplateTask = true;
			recTopTemplateTask.duration = current.u_duration;
		}
		if(current.u_warning_days != previous.u_warning_days){
			updateTemplateTask = true;
			recTopTemplateTask.warning_hours = current.u_warning_days;
		}

		// STRY0084599 - Need a way for deliver and customers to better synchronize field updates and changes
		// when this was added, had to change to always save to simplify for now
		updateTemplateTask = true;
		recTopTemplateTask = new CustomTaskerFieldHelper().mapFieldDataOnAction('templateSyncTopTemplateTask', current, recTopTemplateTask);

		// if any of the sync fields changed, then udpate the Top Template Task, otherwise do not
		// The Top Template Task is also checking these values and updating the Template record
		// When that happens, the buisness rule may fire again.  If it does, the before and after should be the same.
		// this will prevent a recursive loop.
		if(updateTemplateTask){
			// don't run this update method again when the Top Template Task updates it' fields
			recTopTemplateTask.update();
		}
	}


})(current, previous);
